"use client";

import React from "react";
import { useMouse } from "./use-mouse";
import "./full-screen-crosshair.css";

const CrosshairCursor = ({
 color ="#ffffff",
 centerContent ="•",
 hideNativeCursor = true,
 lineSize = 100,
 gap = 20,
 thickness = 1,
 centerSize = 24,
 smooth = true,
 lerpFactor = 0.14,
 blendMode ="normal",
 className ="",
}) => {
 const { smoothMouse } = useMouse({
 smooth,
 lerpFactor,
 });

 return (
 <div
 className={`crosshair-cursor ${hideNativeCursor ?"hide-native-cursor" :""} ${className}`}
 style={{
"--crosshair-color": color,
"--crosshair-line-size": `${lineSize}px`,
"--crosshair-gap": `${gap}px`,
"--crosshair-thickness": `${thickness}px`,
"--crosshair-center-size": `${centerSize}px`,
"--crosshair-blend-mode": blendMode,
 }}
 >
 <div
 className="crosshair-cursor__inner"
 style={{
 transform: `translate3d(${smoothMouse.current.x}px, ${smoothMouse.current.y}px, 0)`,
 }}
 >
 <span className="crosshair-cursor__line crosshair-cursor__line--top" />
 <span className="crosshair-cursor__line crosshair-cursor__line--right" />
 <span className="crosshair-cursor__line crosshair-cursor__line--bottom" />
 <span className="crosshair-cursor__line crosshair-cursor__line--left" />

 <div className="crosshair-cursor__center">
 {centerContent}
 </div>
 </div>
 </div>
 );
};

export default CrosshairCursor;

"use client";
import { useEffect, useRef, useState } from "react";

const lerp = (a, b, n) => (1 - n) * a + n * b;

export const useMouse = ({
 smooth = true,
 lerpFactor = 0.1,
} = {}) => {
 const mouse = useRef({ x: 0, y: 0 });
 const lastMouse = useRef({ x: 0, y: 0 });
 const smoothMouse = useRef({ x: 0, y: 0 });

 const rafRef = useRef(null);

 // Optional state (only if you want re-renders)
 const [state, setState] = useState({
 x: 0,
 y: 0,
 smoothX: 0,
 smoothY: 0,
 dx: 0,
 dy: 0,
 distance: 0,
 });

 const handleMouseMove = (e) => {
 mouse.current = {
 x: e.clientX,
 y: e.clientY,
 };
 };

 const loop = () => {
 const { x, y } = mouse.current;
 const { x: lx, y: ly } = lastMouse.current;

 const dx = x - lx;
 const dy = y - ly;
 const distance = Math.hypot(dx, dy);

 // Smooth interpolation
 if (smooth) {
 smoothMouse.current.x = lerp(smoothMouse.current.x, x, lerpFactor);
 smoothMouse.current.y = lerp(smoothMouse.current.y, y, lerpFactor);
 } else {
 smoothMouse.current.x = x;
 smoothMouse.current.y = y;
 }

 // Update state (if used)
 setState({
 x,
 y,
 smoothX: smoothMouse.current.x,
 smoothY: smoothMouse.current.y,
 dx,
 dy,
 distance,
 });

 lastMouse.current = { x, y };

 rafRef.current = requestAnimationFrame(loop);
 };

 useEffect(() => {
 window.addEventListener("mousemove", handleMouseMove);
 rafRef.current = requestAnimationFrame(loop);

 return () => {
 window.removeEventListener("mousemove", handleMouseMove);
 if (rafRef.current) cancelAnimationFrame(rafRef.current);
 };
 }, []);

 return {
 // RAW values
 x: state.x,
 y: state.y,

 // SMOOTH values (important for animations)
 smoothX: state.smoothX,
 smoothY: state.smoothY,

 // MOVEMENT
 dx: state.dx,
 dy: state.dy,
 distance: state.distance,

 // REFS (for performance-heavy GSAP usage)
 mouse,
 smoothMouse,
 };
};

.crosshair-cursor {
  position: fixed;
  inset: 0;
  z-index: 9999;
  pointer-events: none;
  mix-blend-mode: var(--crosshair-blend-mode, normal);
}

.crosshair-page,
.crosshair-page * {
  cursor: none !important;
}
.crosshair-cursor__inner {
  position: absolute;
  top: 0;
  left: 0;
  width: 0;
  height: 0;
  will-change: transform;
}

.crosshair-cursor__line {
  position: absolute;
  display: block;
  background: var(--crosshair-color, #ffffff);
  transform-origin: center;
}

.crosshair-cursor__line--top {
  width: var(--crosshair-thickness, 1px);
  height: var(--crosshair-line-size, 100px);
  left: 50%;
  top: calc(
    -1 * (var(--crosshair-gap, 20px) + var(--crosshair-line-size, 100px))
  );
  transform: translateX(-50%);
}

.crosshair-cursor__line--right {
  width: var(--crosshair-line-size, 100px);
  height: var(--crosshair-thickness, 1px);
  top: 50%;
  left: var(--crosshair-gap, 20px);
  transform: translateY(-50%);
}

.crosshair-cursor__line--bottom {
  width: var(--crosshair-thickness, 1px);
  height: var(--crosshair-line-size, 100px);
  left: 50%;
  top: var(--crosshair-gap, 20px);
  transform: translateX(-50%);
}

.crosshair-cursor__line--left {
  width: var(--crosshair-line-size, 100px);
  height: var(--crosshair-thickness, 1px);
  top: 50%;
  right: var(--crosshair-gap, 20px);
  transform: translateY(-50%);
}

.crosshair-cursor__center {
  position: absolute;
  top: 50%;
  left: 50%;
  min-width: var(--crosshair-center-size, 24px);
  min-height: var(--crosshair-center-size, 24px);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--crosshair-color, #ffffff);
  font-size: var(--crosshair-center-size, 24px);
  line-height: 1;
  transform: translate(-50%, -50%);
  user-select: none;
  white-space: nowrap;
}

@media (max-width: 1024px) {
  .crosshair-cursor__center {
    font-size: calc(var(--crosshair-center-size, 24px) * 0.9);
  }
}

